() => {
  function getXPath(el) {
    if (!el) return null;
    if (el.id) return '//*[@id="' + el.id + '"]';

    const parts = [];
    while (el && el.nodeType === Node.ELEMENT_NODE) {
      let index = 1;
      let sibling = el.previousElementSibling;

      while (sibling) {
        if (sibling.nodeName === el.nodeName) index++;
        sibling = sibling.previousElementSibling;
      }

      parts.unshift(el.nodeName.toLowerCase() + "[" + index + "]");
      el = el.parentElement;
    }

    return "/" + parts.join("/");
  }

  const products = [];
  const productCards = document.querySelectorAll('.thumbnail');

  for (let i = 0; i < Math.min(10, productCards.length); i++) {
    const card = productCards[i];

    // Get the title link element
    const titleLink = card.querySelector('.title');
    const name = titleLink ? titleLink.textContent.trim() : null;
    const productUrl = titleLink ? new URL(titleLink.getAttribute('href'), window.location.href).href : null;
    const xpath = titleLink ? getXPath(titleLink) : null;

    // Get price
    const priceElement = card.querySelector('.price');
    const price = priceElement ? priceElement.textContent.trim() : null;

    // Get rating - use data-rating attribute or count stars
    const ratingsDiv = card.querySelector('.ratings');
    let rating = null;
    if (ratingsDiv) {
      const ratingPara = ratingsDiv.querySelector('p[data-rating]');
      if (ratingPara) {
        rating = ratingPara.getAttribute('data-rating');
      } else {
        // Fallback: count star icons
        const stars = ratingsDiv.querySelectorAll('.ws-icon-star');
        if (stars.length > 0) {
          rating = stars.length.toString();
        }
      }
    }

    products.push({
      record_id: (i + 1).toString(),
      name: name,
      price: price,
      rating: rating,
      availability: null,
      product_url: productUrl,
      source_url: "https://webscraper.io/test-sites/e-commerce/allinone/computers/laptops",
      source_xpath: xpath
    });
  }

  return products;
}
